import { useEffect, useState } from "react";
import axios from "axios";
import "./SubmitBug.scss";

export default function SubmitBug() {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [severity, setSeverity] = useState("low");
  const [company, setCompany] = useState("");
  const [companies, setCompanies] = useState([]);
  const [message, setMessage] = useState("");

  useEffect(() => {
    // 🔥 Fetch companies for dropdown
    axios
      .get("http://localhost:5000/api/auth/companies")
      .then((res) => setCompanies(res.data))
      .catch((err) => console.error("COMPANY FETCH ERROR", err));
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage("");

    try {
      const token = localStorage.getItem("token");

      await axios.post(
        "http://localhost:5000/api/bugs/submit",
        {
          title,
          description,
          severity, // already lowercase
          company,  // ✅ REQUIRED
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      setMessage("✅ Bug submitted successfully");
      setTitle("");
      setDescription("");
      setSeverity("low");
      setCompany("");
    } catch (err) {
      console.error(err);
      setMessage("❌ Failed to submit bug");
    }
  };

  return (
    <div className="submit-bug-page">
      <form className="submit-card" onSubmit={handleSubmit}>
        <h2>🐞 Submit Vulnerability</h2>

        {message && <p className="message">{message}</p>}

        <input
          placeholder="Bug Title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          required
        />

        <textarea
          placeholder="Describe the vulnerability"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          required
        />

        {/* COMPANY */}
        <select
          value={company}
          onChange={(e) => setCompany(e.target.value)}
          required
        >
          <option value="">Select Company</option>
          {companies.map((c) => (
            <option key={c._id} value={c._id}>
              {c.email}
            </option>
          ))}
        </select>

        {/* SEVERITY */}
        <select
          value={severity}
          onChange={(e) => setSeverity(e.target.value)}
        >
          <option value="low">Low</option>
          <option value="medium">Medium</option>
          <option value="high">High</option>
          <option value="critical">Critical</option>
        </select>

        <button type="submit">Submit Bug</button>
      </form>
    </div>
  );
}
